class Solution {
public:
    int paths(vector<vector<int>>& grid) {
        int m = grid.size(), n = grid[0].size();
        for (int i = m - 2; i >= 0; i--) {
            for (int j = n - 2; j >= 0; j--) {
                if (grid[i][j] == 1) {
                    int count = 0;
                    if (i < m - 1) count += grid[i + 1][j];
                    if (j < n - 1) count += grid[i][j + 1];
                    grid[i][j] = count;
                }
            }
        }
        return grid[0][0];
    }
};

int main() {
    int n, m;
    std::cin >> n >> m;
    vector<vector<int>> grid(n, vector<int>(m));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            std::cin >> grid[i][j];
        }
    }
    Solution s;
    std::cout << s.paths(grid) << std::endl;
    return 0;
}

